export interface ProjectExplorerProject {
  createdAt: Date | string;
  id: string;
  /** Display name (preferred: `spec.title` when set on the claim). */
  name: string;
  /** `spec.public` on the Project claim when known. */
  public?: boolean;
  /** Kubernetes `metadata.name`; defaults to `name` when omitted (legacy rows). */
  resourceName?: string;
}

/** Copy shown when `projects` is empty (list uses defaults when fields are omitted). */
export interface ProjectExplorerEmptyState {
  /** Set to `""` to hide the secondary line. */
  description?: string;
  title?: string;
}

/** Display state for the explorer (passed into Root as `states`). */
export interface ProjectExplorerStates {
  /**
   * When `projects` has no items, the list shows an empty state.
   * Set `title` / `description` to customize; strings default when omitted.
   */
  empty?: ProjectExplorerEmptyState;
  projects: ProjectExplorerProject[];
}

/** Optional handlers for project rows. */
export interface ProjectExplorerActions {
  /** Opens the create-project flow when the header action is used. */
  onNewProject?: () => void;
  onProjectClick?: (project: ProjectExplorerProject) => void;
  onProjectDelete?: (project: ProjectExplorerProject) => void | Promise<void>;
  /**
   * Display rename; typically PATCH `spec.title` while keeping `metadata.name`
   * ({@link ProjectExplorerProject.resourceName}).
   */
  onProjectRename?: (
    project: ProjectExplorerProject,
    newDisplayName: string
  ) => void | Promise<void>;
}

export interface ProjectExplorerValue {
  actions: ProjectExplorerActions;
  searchQuery: string;
  setSearchQuery: (query: string) => void;
  states: ProjectExplorerStates;
}

export function toDate(value: Date | string): Date {
  return value instanceof Date ? value : new Date(value);
}

export function formatCreatedAt(value: Date | string): string {
  const d = toDate(value);
  return new Intl.DateTimeFormat(undefined, {
    dateStyle: "medium",
    timeStyle: "short",
  }).format(d);
}

"use client";

import {
  createContext,
  type ReactNode,
  useContext,
  useMemo,
  useState,
} from "react";

import type {
  ProjectExplorerActions,
  ProjectExplorerStates,
  ProjectExplorerValue,
} from "./project-explorer.types";

export const ProjectExplorerContext =
  createContext<ProjectExplorerValue | null>(null);

export function useProjectExplorer(): ProjectExplorerValue {
  const value = useContext(ProjectExplorerContext);
  if (!value) {
    throw new Error(
      "ProjectExplorer: useProjectExplorer must be used within ProjectExplorer.Root"
    );
  }
  return value;
}

export function ProjectExplorerRoot({
  actions = {},
  children,
  states,
}: {
  actions?: ProjectExplorerActions;
  children?: ReactNode;
  states: ProjectExplorerStates;
}) {
  const [searchQuery, setSearchQuery] = useState("");

  const value = useMemo(
    (): ProjectExplorerValue => ({
      actions,
      searchQuery,
      setSearchQuery,
      states,
    }),
    [actions, searchQuery, states]
  );

  return (
    <ProjectExplorerContext.Provider value={value}>
      {children}
    </ProjectExplorerContext.Provider>
  );
}

"use client";

import { cn } from "@workspace/ui/lib/utils";
import type { ComponentProps, ReactNode } from "react";

/** Outer chrome for the explorer (opinionated shadow + column flex). */
export function ProjectExplorerShell({
  className,
  ...props
}: ComponentProps<"div">) {
  return (
    <div
      className={cn(
        "flex min-w-0 flex-1 flex-col overflow-hidden text-sm shadow-xs",
        className
      )}
      {...props}
    />
  );
}

/** Region shell: padding only; compose {@link ProjectExplorerHeaderBrand}, toolbar leaves, etc. as `children`. */
export function ProjectExplorerHeader({
  className,
  children,
  ...props
}: ComponentProps<"div"> & { children?: ReactNode }) {
  return (
    <div className={cn("px-4 py-3", className)} {...props}>
      {children}
    </div>
  );
}

"use client";

import { Button } from "@workspace/ui/components/button";
import { Input } from "@workspace/ui/components/input";
import { cn } from "@workspace/ui/lib/utils";
import { LayoutGrid, Plus, Search } from "lucide-react";
import type { ComponentProps } from "react";

import { useProjectExplorer } from "./project-explorer.context";

/** Title row: grid icon + “Projects” label. */
export function ProjectExplorerHeaderBrand({
  className,
  label = "Projects",
  ...props
}: ComponentProps<"div"> & { label?: string }) {
  return (
    <div
      className={cn("flex items-center gap-2", className)}
      data-slot="project-explorer-header-brand"
      {...props}
    >
      <LayoutGrid
        aria-hidden
        className="size-4 shrink-0 text-muted-foreground"
      />
      <div className="text-start font-mono text-base text-foreground leading-none">
        {label}
      </div>
    </div>
  );
}

/** Second-row wrapper: search + actions (`min-w-0` flex row). */
export function ProjectExplorerHeaderToolbar({
  className,
  ...props
}: ComponentProps<"div">) {
  return (
    <div
      className={cn("flex min-w-0 items-center gap-2", className)}
      data-slot="project-explorer-header-toolbar"
      {...props}
    />
  );
}

/** Search field wired to explorer context (`searchQuery` / `setSearchQuery`). */
export function ProjectExplorerSearchField({
  className,
  placeholder = "Search projects…",
  ...props
}: Omit<ComponentProps<typeof Input>, "onChange" | "type" | "value"> & {
  placeholder?: string;
}) {
  const { searchQuery, setSearchQuery } = useProjectExplorer();

  return (
    <div
      className={cn("relative min-w-0 flex-1", className)}
      data-slot="project-explorer-search-field"
    >
      <Search
        aria-hidden
        className="pointer-events-none absolute top-1/2 left-2.5 size-4 -translate-y-1/2 text-muted-foreground"
      />
      <Input
        aria-label="Search projects"
        className="h-8 pl-9 shadow-xs"
        onChange={(e) => setSearchQuery(e.target.value)}
        placeholder={placeholder}
        type="search"
        value={searchQuery}
        {...props}
      />
    </div>
  );
}

/** Primary “New project” control; calls `actions.onNewProject` when set. */
export function ProjectExplorerNewProjectButton({
  className,
  children,
  ...props
}: ComponentProps<typeof Button>) {
  const { actions } = useProjectExplorer();
  const { onClick, ...rest } = props;

  return (
    <Button
      className={className}
      size="lg"
      type="button"
      variant="default"
      {...rest}
      onClick={(e) => {
        onClick?.(e);
        if (!e.defaultPrevented) {
          actions.onNewProject?.();
        }
      }}
    >
      {children ?? (
        <>
          <Plus aria-hidden className="size-4" />
          New Project
        </>
      )}
    </Button>
  );
}

"use client";

import { cn } from "@workspace/ui/lib/utils";

import { useProjectExplorer } from "./project-explorer.context";
import { ProjectExplorerListItem } from "./project-explorer.list-item";
import type { ProjectExplorerProject } from "./project-explorer.types";

const DEFAULT_EMPTY_TITLE = "No projects yet";
const DEFAULT_EMPTY_DESCRIPTION = "Create a project to see it here.";
const NO_MATCH_TITLE = "No matching projects";
const NO_MATCH_DESCRIPTION = "Try a different search.";

function filterProjectsByQuery(
  projects: ProjectExplorerProject[],
  searchQuery: string
): ProjectExplorerProject[] {
  const q = searchQuery.trim().toLowerCase();
  if (q === "") {
    return projects;
  }
  return projects.filter((p) => p.name.toLowerCase().includes(q));
}

export function ProjectExplorerList({ className }: { className?: string }) {
  const { searchQuery, states } = useProjectExplorer();
  const { projects, empty } = states;
  const filteredProjects = filterProjectsByQuery(projects, searchQuery);

  if (projects.length === 0) {
    const title = empty?.title?.trim() || DEFAULT_EMPTY_TITLE;
    const description =
      empty?.description === undefined
        ? DEFAULT_EMPTY_DESCRIPTION
        : empty.description.trim() || null;

    return (
      <div className={cn(className)} data-slot="project-explorer-list">
        <div
          className="flex flex-col items-center justify-center rounded-xl px-4 py-10 text-center"
          data-slot="project-explorer-empty"
        >
          <p className="font-medium text-foreground text-sm">{title}</p>
          {description ? (
            <p className="mt-1.5 max-w-sm text-balance text-muted-foreground text-xs leading-relaxed">
              {description}
            </p>
          ) : null}
        </div>
      </div>
    );
  }

  if (filteredProjects.length === 0) {
    return (
      <div className={cn(className)} data-slot="project-explorer-list">
        <div
          className="flex flex-col items-center justify-center rounded-xl px-4 py-10 text-center"
          data-slot="project-explorer-filter-empty"
        >
          <p className="font-medium text-foreground text-sm">
            {NO_MATCH_TITLE}
          </p>
          <p className="mt-1.5 max-w-sm text-balance text-muted-foreground text-xs leading-relaxed">
            {NO_MATCH_DESCRIPTION}
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className={cn(className)} data-slot="project-explorer-list">
      <ul className="flex flex-col gap-2">
        {filteredProjects.map((project) => (
          <ProjectExplorerListItem key={project.id} project={project} />
        ))}
      </ul>
    </div>
  );
}

"use client";

import {
  AlertDialog,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@workspace/ui/components/alert-dialog";
import { Button } from "@workspace/ui/components/button";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@workspace/ui/components/dialog";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@workspace/ui/components/dropdown-menu";
import { Input } from "@workspace/ui/components/input";
import { Label } from "@workspace/ui/components/label";
import { cn } from "@workspace/ui/lib/utils";
import { EllipsisVertical, Pencil, Trash2 } from "lucide-react";
import { type KeyboardEvent, useCallback, useEffect, useState } from "react";

import { useProjectExplorer } from "./project-explorer.context";
import type { ProjectExplorerProject } from "./project-explorer.types";
import { formatCreatedAt, toDate } from "./project-explorer.utils";

function k8sName(project: ProjectExplorerProject): string {
  return project.resourceName ?? project.name;
}

export function ProjectExplorerListItem({
  className,
  project,
}: {
  className?: string;
  project: ProjectExplorerProject;
}) {
  const { actions } = useProjectExplorer();
  const interactive = actions.onProjectClick != null;
  const canRename = actions.onProjectRename != null;
  const canDelete = actions.onProjectDelete != null;
  const showRowMenu = canRename || canDelete;

  const [renameOpen, setRenameOpen] = useState(false);
  const [deleteOpen, setDeleteOpen] = useState(false);
  const [renameDraft, setRenameDraft] = useState(project.name);
  const [renameBusy, setRenameBusy] = useState(false);
  const [deleteBusy, setDeleteBusy] = useState(false);

  useEffect(() => {
    if (renameOpen) {
      setRenameDraft(project.name);
    }
  }, [renameOpen, project.name]);

  const created = toDate(project.createdAt);
  const iso = Number.isNaN(created.getTime())
    ? undefined
    : created.toISOString();

  const handleRowActivate = useCallback(() => {
    actions.onProjectClick?.(project);
  }, [actions, project]);

  const handleRowKeyDown = useCallback(
    (event: KeyboardEvent<HTMLDivElement>) => {
      if (event.key === "Enter" || event.key === " ") {
        event.preventDefault();
        handleRowActivate();
      }
    },
    [handleRowActivate]
  );

  const submitRename = useCallback(async () => {
    const next = renameDraft.trim();
    if (next === "" || next === project.name) {
      setRenameOpen(false);
      return;
    }
    if (!actions.onProjectRename) {
      return;
    }
    setRenameBusy(true);
    try {
      await actions.onProjectRename(project, next);
      setRenameOpen(false);
    } finally {
      setRenameBusy(false);
    }
  }, [actions, project, renameDraft]);

  const submitDelete = useCallback(async () => {
    if (!actions.onProjectDelete) {
      return;
    }
    setDeleteBusy(true);
    try {
      await actions.onProjectDelete(project);
      setDeleteOpen(false);
    } finally {
      setDeleteBusy(false);
    }
  }, [actions, project]);

  return (
    <li
      className={cn("rounded-xl px-4", className)}
      data-slot="project-explorer-item"
    >
      <div className="hoverable flex min-w-0 items-center gap-2 rounded-xl p-3 sm:gap-3">
        <div
          className={cn(
            "flex min-w-0 flex-1 flex-row items-baseline justify-between gap-3 text-start",
            interactive && "cursor-pointer"
          )}
          {...(interactive
            ? {
                role: "button" as const,
                tabIndex: 0,
                onClick: handleRowActivate,
                onKeyDown: handleRowKeyDown,
              }
            : {})}
        >
          <span className="min-w-0 truncate font-medium text-foreground text-sm">
            {project.name}
          </span>
          <time
            className="shrink-0 text-muted-foreground text-xs tabular-nums"
            dateTime={iso}
          >
            {formatCreatedAt(project.createdAt)}
          </time>
        </div>
        {showRowMenu ? (
          <DropdownMenu>
            <DropdownMenuTrigger
              render={
                <Button
                  aria-label={`Actions for ${project.name}`}
                  className="shrink-0"
                  onClick={(e) => e.stopPropagation()}
                  onPointerDown={(e) => e.stopPropagation()}
                  size="icon-sm"
                  type="button"
                  variant="ghost"
                />
              }
            >
              <EllipsisVertical aria-hidden className="size-4" />
            </DropdownMenuTrigger>
            <DropdownMenuContent align="end" className="min-w-40">
              {canRename ? (
                <DropdownMenuItem onClick={() => setRenameOpen(true)}>
                  <Pencil aria-hidden className="size-4" />
                  Rename
                </DropdownMenuItem>
              ) : null}
              {canDelete ? (
                <DropdownMenuItem
                  onClick={() => setDeleteOpen(true)}
                  variant="destructive"
                >
                  <Trash2 aria-hidden className="size-4" />
                  Delete
                </DropdownMenuItem>
              ) : null}
            </DropdownMenuContent>
          </DropdownMenu>
        ) : null}
      </div>

      <Dialog onOpenChange={setRenameOpen} open={renameOpen}>
        <DialogContent
          className="gap-4"
          data-slot="project-explorer-rename-dialog"
          onClick={(e) => e.stopPropagation()}
          showCloseButton
        >
          <DialogHeader>
            <DialogTitle>Rename project</DialogTitle>
            <DialogDescription>
              Updates the display name for{" "}
              <span className="font-medium text-foreground">
                {project.name}
              </span>{" "}
              (resource{" "}
              <span className="font-mono text-foreground">
                {k8sName(project)}
              </span>
              ).
            </DialogDescription>
          </DialogHeader>
          <div className="flex flex-col gap-2">
            <Label htmlFor={`project-rename-${project.id}`}>Name</Label>
            <Input
              autoComplete="off"
              id={`project-rename-${project.id}`}
              onChange={(e) => setRenameDraft(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === "Enter") {
                  e.preventDefault();
                  submitRename().catch(() => undefined);
                }
              }}
              value={renameDraft}
            />
          </div>
          <DialogFooter className="gap-2 sm:gap-0">
            <Button
              disabled={renameBusy}
              onClick={() => setRenameOpen(false)}
              type="button"
              variant="outline"
            >
              Cancel
            </Button>
            <Button
              disabled={
                renameBusy ||
                renameDraft.trim() === "" ||
                renameDraft.trim() === project.name
              }
              onClick={() => submitRename().catch(() => undefined)}
              type="button"
            >
              Save
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <AlertDialog onOpenChange={setDeleteOpen} open={deleteOpen}>
        <AlertDialogContent
          data-slot="project-explorer-delete-dialog"
          onClick={(e) => e.stopPropagation()}
        >
          <AlertDialogHeader>
            <AlertDialogTitle>Delete project?</AlertDialogTitle>
            <AlertDialogDescription>
              This will delete{" "}
              <span className="font-medium text-foreground">
                {project.name}
              </span>{" "}
              (<span className="font-mono">{k8sName(project)}</span>) from the
              cluster. This cannot be undone.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel disabled={deleteBusy}>Cancel</AlertDialogCancel>
            <Button
              className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
              disabled={deleteBusy}
              onClick={(e) => {
                e.stopPropagation();
                submitDelete().catch(() => undefined);
              }}
              type="button"
              variant="destructive"
            >
              Delete
            </Button>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </li>
  );
}

